import pytest

def test_parse_thinking_budget_valid_values(parse_thinking_budget):
    assert parse_thinking_budget("high") == 16384
    assert parse_thinking_budget("medium") == 8192
    assert parse_thinking_budget("low") == 1024
    assert parse_thinking_budget("4096") == 4096
    assert parse_thinking_budget("0") == 0


def test_parse_thinking_budget_invalid_values(parse_thinking_budget):
    with pytest.raises(ValueError):
        parse_thinking_budget("invalid")
    with pytest.raises(ValueError):
        parse_thinking_budget("-1")
    with pytest.raises(ValueError):
        parse_thinking_budget("")


@pytest.fixture
def parse_thinking_budget():
    def _parse(s: str) -> int:
        presets = {"high": 16384, "medium": 8192, "low": 1024}
        s = s.strip()
        if s in presets:
            return presets[s]
        try:
            val = int(s)
        except ValueError:
            raise ValueError(f"Invalid thinking budget: {s!r}")
        if val < 0:
            raise ValueError(f"Budget must be non-negative, got {val}")
        return val

    return _parse
